import{_ as a,o,c as e,a3 as r}from"./chunks/framework.BTFg6ESq.js";const g=JSON.parse('{"title":"LLM 检查器","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-inspector.md","filePath":"user-guide/tools/llm-inspector.md","lastUpdated":1778221347000}'),l={name:"user-guide/tools/llm-inspector.md"};function i(n,t,s,d,h,c){return o(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="llm-检查器" tabindex="-1">LLM 检查器 <a class="header-anchor" href="#llm-检查器" aria-label="Permalink to &quot;LLM 检查器&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>LLM 检查器是一个<strong>本地中间人代理工具</strong>，专门用于监听、捕获和分析 AI 客户端与 LLM API 之间的网络通信。它就像一根&quot;探针&quot;插在你的 AI 应用和 API 服务之间，让你能清晰看到每个请求的完整面貌。</p><h3 id="典型场景" tabindex="-1">典型场景 <a class="header-anchor" href="#典型场景" aria-label="Permalink to &quot;典型场景&quot;">​</a></h3><ul><li><strong>调试 AI 应用</strong>：想知道你的 AI 客户端到底发了什么系统提示词？打开 LLM 检查器看看</li><li><strong>对比不同客户端</strong>：同一个 API，不同客户端构造的请求体有什么区别？捕获对比一目了然</li><li><strong>排查 API 通信问题</strong>：请求莫名其妙失败？检查器帮你还原请求头和请求体的真实面貌</li><li><strong>学习 LLM API 协议</strong>：想了解流式响应的 SSE 格式长什么样？捕获一个实时流看看</li></ul><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>一键启动/停止的本地代理</strong>：配置端口和目标地址，点击启动即可开始捕获</li><li><strong>实时请求记录</strong>：自动捕获每个经过代理的 HTTP 请求，按时间顺序排列</li><li><strong>完整的请求/响应详情</strong>：展开任意记录查看完整的请求头、请求体、响应头和响应体</li><li><strong>流式数据实时展示</strong>：支持 SSE（Server-Sent Events）流式响应，实时累积显示数据块</li><li><strong>智能搜索与过滤</strong>：支持按关键词搜索 URL，按状态（处理中/已完成）过滤记录</li><li><strong>API Key 打码保护</strong>：复制请求信息时自动隐藏敏感 API Key，避免误泄露</li><li><strong>请求头覆盖规则</strong>：可配置自定义的请求头覆盖规则，灵活修改转发时的请求头</li><li><strong>活跃流计数</strong>：实时显示当前有多少个流式请求正在进行中</li><li><strong>目标地址历史</strong>：历史输入的目标地址自动保存，下次使用自动补全</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="三步完成第一次捕获" tabindex="-1">三步完成第一次捕获 <a class="header-anchor" href="#三步完成第一次捕获" aria-label="Permalink to &quot;三步完成第一次捕获&quot;">​</a></h3><p><strong>第一步：进入工具</strong></p><p>在左侧工具列表中找到 <strong>LLM 检查器</strong>，点击进入。你将看到一个顶部配置面板 + 左右分栏记录列表的界面。</p><blockquote><p>TODO: 截图 - LLM 检查器整体界面，标注配置面板、记录列表和详情区域</p></blockquote><p><strong>第二步：配置并启动</strong></p><p>在顶部的配置面板中：</p><ol><li><strong>设置监听端口</strong>（默认 <code>8999</code>），确保端口未被其他服务占用</li><li><strong>输入目标 API 地址</strong>，例如你要监听 OpenAI 的请求就填 <code>https://api.openai.com</code></li><li>点击 <strong>启动检查器</strong> 按钮</li></ol><p>启动成功后，状态栏会显示绿色指示灯和运行中的代理地址（如 <code>http://localhost:8999</code>）。</p><blockquote><p>TODO: 截图 - 配置面板填写好端口和地址，点击启动按钮后的状态</p></blockquote><p><strong>第三步：让 AI 客户端指向代理</strong></p><p>回到你的 AI 客户端（比如 NextChat、Open WebUI 或你的自定义应用），修改 API 地址指向代理：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原地址：https://api.openai.com/v1/chat/completions</span></span>
<span class="line"><span>改为：  http://localhost:8999/v1/chat/completions</span></span></code></pre></div><p>现在正常使用你的 AI 客户端，每一次请求都会先经过 LLM 检查器，所有通信内容都会被记录下来。</p><blockquote><p>TODO: 截图 - 客户端配置代理地址的界面</p></blockquote><h3 id="查看捕获结果" tabindex="-1">查看捕获结果 <a class="header-anchor" href="#查看捕获结果" aria-label="Permalink to &quot;查看捕获结果&quot;">​</a></h3><p>配置面板下方分左右两栏：</p><ul><li><strong>左侧（记录列表）</strong>：按时间倒序排列所有捕获的请求，每行显示方法（POST/GET 等）、URL 路径片段和当前状态（🟡 处理中 / ✅ 已完成）</li><li><strong>右侧（记录详情）</strong>：点击某条记录后，右侧展示该请求的完整信息，包括请求头、请求体、响应头、响应体</li></ul><blockquote><p>TODO: 截图 - 捕获到请求后，左侧列表和右侧详情的对应状态</p></blockquote><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="配置面板" tabindex="-1">配置面板 <a class="header-anchor" href="#配置面板" aria-label="Permalink to &quot;配置面板&quot;">​</a></h3><p>配置面板位于界面顶部，包含所有控制选项。</p><h4 id="端口与启动控制" tabindex="-1">端口与启动控制 <a class="header-anchor" href="#端口与启动控制" aria-label="Permalink to &quot;端口与启动控制&quot;">​</a></h4><table tabindex="0"><thead><tr><th>控件</th><th>说明</th></tr></thead><tbody><tr><td><strong>端口输入框</strong></td><td>设置本地监听端口，范围 <code>1024-65535</code>，服务运行中不可修改</td></tr><tr><td><strong>启动/停止按钮</strong></td><td>绿色启动、红色停止，点击切换检查器运行状态</td></tr><tr><td><strong>清空记录</strong></td><td>一键清空所有已捕获的记录，不影响检查器运行</td></tr></tbody></table><h4 id="目标地址" tabindex="-1">目标地址 <a class="header-anchor" href="#目标地址" aria-label="Permalink to &quot;目标地址&quot;">​</a></h4><p>可输入任意 HTTP/HTTPS API 地址，如 <code>https://api.openai.com</code>、<code>https://api.deepseek.com</code> 等。输入框带有自动补全功能，会记住你之前输入的地址历史。</p><p>当检查器正在运行时，修改目标地址后需点击 <strong>更新地址</strong> 按钮使其生效——这在你想切换监听不同 API 服务时特别方便，无需停止再启动。</p><blockquote><p>TODO: 截图 - 目标地址输入框的自动补全下拉</p></blockquote><h4 id="请求头设置" tabindex="-1">请求头设置 <a class="header-anchor" href="#请求头设置" aria-label="Permalink to &quot;请求头设置&quot;">​</a></h4><p>点击 <strong>请求头设置</strong> 按钮，打开请求头覆盖规则管理对话框。在这里你可以：</p><ul><li><strong>添加规则</strong>：指定要覆盖或新增的请求头键名（如 <code>User-Agent</code>）和值</li><li><strong>启用/禁用规则</strong>：每条规则可独立开关，方便临时开启或关闭</li><li><strong>自定义转发</strong>：某些 API 需要特殊请求头才能正常通信，用此功能即可灵活适配</li></ul><blockquote><p>TODO: 截图 - 请求头覆盖规则管理对话框</p></blockquote><h4 id="统计信息" tabindex="-1">统计信息 <a class="header-anchor" href="#统计信息" aria-label="Permalink to &quot;统计信息&quot;">​</a></h4><p>配置面板中的统计栏显示三个关键指标：</p><table tabindex="0"><thead><tr><th>指标</th><th>说明</th></tr></thead><tbody><tr><td><strong>总记录</strong></td><td>检查器启动以来捕获的所有请求数</td></tr><tr><td><strong>已完成</strong></td><td>已收到完整响应的请求数</td></tr><tr><td><strong>处理中</strong></td><td>正在等待响应的请求数（通常为流式请求）</td></tr></tbody></table><blockquote><p>TODO: 截图 - 统计信息区域</p></blockquote><h4 id="api-key-打码开关" tabindex="-1">API Key 打码开关 <a class="header-anchor" href="#api-key-打码开关" aria-label="Permalink to &quot;API Key 打码开关&quot;">​</a></h4><p>勾选 <strong>复制时打码 API Key</strong> 后，在记录详情中复制请求体或响应体时，API Key 相关的字段值会被自动替换为 <code>***</code>。推荐在需要分享或导出捕获内容时开启此功能。</p><h3 id="记录列表" tabindex="-1">记录列表 <a class="header-anchor" href="#记录列表" aria-label="Permalink to &quot;记录列表&quot;">​</a></h3><p>位于左下区域的记录列表展示所有捕获的请求记录。</p><h4 id="搜索与过滤" tabindex="-1">搜索与过滤 <a class="header-anchor" href="#搜索与过滤" aria-label="Permalink to &quot;搜索与过滤&quot;">​</a></h4><p>列表顶部提供：</p><ul><li><strong>搜索框</strong>：输入关键词，实时过滤匹配 URL 的记录</li><li><strong>状态筛选</strong>：下拉选择「全部」「处理中」「已完成」，快速定位特定状态的请求</li></ul><blockquote><p>TODO: 截图 - 搜索框和状态筛选下拉框</p></blockquote><h4 id="记录条目" tabindex="-1">记录条目 <a class="header-anchor" href="#记录条目" aria-label="Permalink to &quot;记录条目&quot;">​</a></h4><p>每条记录显示：</p><ul><li><strong>HTTP 方法</strong>（如 <code>POST</code>）</li><li><strong>URL 路径</strong>（如 <code>/v1/chat/completions</code>）</li><li><strong>状态标识</strong>：🟡 表示请求已收到但响应尚未完成（流式请求正在传输中），✅ 表示请求已完成</li><li><strong>时间戳</strong>：请求发起的时间</li></ul><h3 id="记录详情" tabindex="-1">记录详情 <a class="header-anchor" href="#记录详情" aria-label="Permalink to &quot;记录详情&quot;">​</a></h3><p>点击某条记录后，右侧详情区域展示完整的请求/响应信息。</p><h4 id="请求信息" tabindex="-1">请求信息 <a class="header-anchor" href="#请求信息" aria-label="Permalink to &quot;请求信息&quot;">​</a></h4><table tabindex="0"><thead><tr><th>区域</th><th>内容</th></tr></thead><tbody><tr><td><strong>请求头</strong></td><td>逐行展示所有 HTTP 请求头，键值对形式</td></tr><tr><td><strong>请求体</strong></td><td>原始请求体内容，JSON 格式会保留原始缩进</td></tr><tr><td><strong>请求大小</strong></td><td>请求体的字节数</td></tr></tbody></table><h4 id="响应信息" tabindex="-1">响应信息 <a class="header-anchor" href="#响应信息" aria-label="Permalink to &quot;响应信息&quot;">​</a></h4><table tabindex="0"><thead><tr><th>区域</th><th>内容</th></tr></thead><tbody><tr><td><strong>状态码</strong></td><td>HTTP 状态码（如 <code>200 OK</code>）</td></tr><tr><td><strong>响应头</strong></td><td>完整的响应头列表</td></tr><tr><td><strong>响应体</strong></td><td>完整的响应内容；如果是流式响应，会累积显示所有收到的数据块</td></tr><tr><td><strong>响应大小</strong></td><td>响应体的字节数</td></tr><tr><td><strong>耗时</strong></td><td>从请求发出到收到完整响应的耗时（毫秒）</td></tr></tbody></table><blockquote><p>TODO: 截图 - 记录详情面板，标注请求头、请求体、响应头、响应体区域</p></blockquote><h4 id="流式响应实时展示" tabindex="-1">流式响应实时展示 <a class="header-anchor" href="#流式响应实时展示" aria-label="Permalink to &quot;流式响应实时展示&quot;">​</a></h4><p>当捕获的是流式请求（SSE）时，详情面板中的响应体会<strong>实时更新</strong>——你可以看到内容逐段增加，就像在 AI 聊天界面中看到逐字输出一样。详情面板顶部还会显示该记录的活跃流状态。</p><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="同时监听多个-api-服务" tabindex="-1">同时监听多个 API 服务 <a class="header-anchor" href="#同时监听多个-api-服务" aria-label="Permalink to &quot;同时监听多个 API 服务&quot;">​</a></h3><p>LLM 检查器在同一时间只能监听一个目标地址。如果你需要切换监听不同的 API 服务：</p><ol><li>在配置面板修改目标地址</li><li>点击 <strong>更新地址</strong> 按钮</li><li>检查器会自动将后续请求转发到新地址，无需停止重启</li></ol><p>这样你就可以在同一会话中连续捕获 OpenAI、Anthropic 和本地模型等多个服务。</p><h3 id="对比不同客户端的请求差异" tabindex="-1">对比不同客户端的请求差异 <a class="header-anchor" href="#对比不同客户端的请求差异" aria-label="Permalink to &quot;对比不同客户端的请求差异&quot;">​</a></h3><p>假设你想了解两个 AI 客户端对同一 API 的调用差异：</p><ol><li>启动 LLM 检查器，目标地址设为目标 API</li><li>客户端 A 发送一条消息 → 捕获记录 #1</li><li>客户端 B 发送同样的消息 → 捕获记录 #2</li><li>在记录列表中分别点开两条记录，对比它们的请求体、请求头差异</li></ol><blockquote><p>💡 <strong>小提示</strong>：可以结合 <strong>API Key 打码</strong> 功能，在对比时屏蔽掉认证信息的干扰。</p></blockquote><h3 id="调试自定义工具的-api-调用" tabindex="-1">调试自定义工具的 API 调用 <a class="header-anchor" href="#调试自定义工具的-api-调用" aria-label="Permalink to &quot;调试自定义工具的 API 调用&quot;">​</a></h3><p>如果你正在开发一个调用 LLM API 的工具或应用：</p><ol><li>在开发阶段将 API 地址指向 LLM 检查器</li><li>触发一次 API 调用</li><li>在检查器中查看完整的请求详情——确认请求头、请求体和 URL 是否正确</li><li>如果调用失败，查看响应体内的错误信息定位问题</li></ol><h3 id="请求头覆盖规则的实际应用" tabindex="-1">请求头覆盖规则的实际应用 <a class="header-anchor" href="#请求头覆盖规则的实际应用" aria-label="Permalink to &quot;请求头覆盖规则的实际应用&quot;">​</a></h3><p>某些 LLM 服务商要求特定的请求头才能正常响应（如 Anthropic 需要 <code>anthropic-version</code>）。通过配置请求头覆盖规则，你可以：</p><ul><li><strong>补全缺失的头</strong>：客户端未发送但服务端要求的头</li><li><strong>覆盖已有的头</strong>：修改客户端发出的某些请求头以满足特定需求</li><li><strong>添加测试标记</strong>：在测试环境中添加自定义的跟踪头</li></ul><h3 id="记录管理与分析" tabindex="-1">记录管理与分析 <a class="header-anchor" href="#记录管理与分析" aria-label="Permalink to &quot;记录管理与分析&quot;">​</a></h3><p>当捕获了大量记录时：</p><ul><li>使用 <strong>搜索框</strong> 按 URL 关键词快速定位特定请求</li><li>使用 <strong>状态筛选</strong> 只查看已完成或仍在处理中的请求</li><li>需要重新捕获时点击 <strong>清空记录</strong>，从干净状态开始</li><li>在详情面板中直接复制请求/响应内容到剪贴板，便于外部分析</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-启动检查器后-我的-ai-客户端连接失败-怎么办" tabindex="-1">Q：启动检查器后，我的 AI 客户端连接失败，怎么办？ <a class="header-anchor" href="#q-启动检查器后-我的-ai-客户端连接失败-怎么办" aria-label="Permalink to &quot;Q：启动检查器后，我的 AI 客户端连接失败，怎么办？&quot;">​</a></h3><p>按以下步骤排查：</p><ol><li>检查检查器状态指示灯是否为绿色——确认服务正在运行</li><li>确认你已在 AI 客户端中将 API 地址的域名部分替换为 <code>http://localhost:8999</code></li><li>检查端口是否被其他程序占用——可以换一个端口（如 <code>8998</code>）试试</li><li>系统防火墙可能阻止了本地连接——检查防火墙规则是否允许本地端口通信</li><li>如果客户端要求 HTTPS 连接，而本地代理是 HTTP，需要更换支持 HTTPS 的客户端或使用其他调试方式</li></ol><h3 id="q-为什么我捕获到的响应体是空的" tabindex="-1">Q：为什么我捕获到的响应体是空的？ <a class="header-anchor" href="#q-为什么我捕获到的响应体是空的" aria-label="Permalink to &quot;Q：为什么我捕获到的响应体是空的？&quot;">​</a></h3><p>可能的原因：</p><ul><li><strong>流式请求尚未完成</strong>：如果记录状态是&quot;处理中&quot;，说明流式传输还在进行中，等待传输完成即可看到完整响应体</li><li><strong>请求本身无响应体</strong>：某些 HTTP 方法（如 <code>DELETE</code>）或特定 API 端点可能不返回响应体</li><li><strong>响应体过大</strong>：检查器对请求/响应体大小有一定限制，超大响应可能被截断</li></ul><h3 id="q-stream-流式-模式下的实时数据怎么看" tabindex="-1">Q：Stream（流式）模式下的实时数据怎么看？ <a class="header-anchor" href="#q-stream-流式-模式下的实时数据怎么看" aria-label="Permalink to &quot;Q：Stream（流式）模式下的实时数据怎么看？&quot;">​</a></h3><p>LLM 检查器天然支持 SSE 流式响应。当你捕获到一个流式请求后：</p><ul><li>记录列表中的该记录状态会保持&quot;处理中&quot;，直到流结束</li><li>右侧详情面板的响应体会不断更新，实时追加新的数据块</li><li>流结束后记录状态变为&quot;已完成&quot;，响应体为完整内容</li><li>配置面板中的 <strong>活跃流计数</strong> 会实时显示当前正在进行的流式请求数量</li></ul><h3 id="q-打码-api-key-功能会影响已保存的记录吗" tabindex="-1">Q：打码 API Key 功能会影响已保存的记录吗？ <a class="header-anchor" href="#q-打码-api-key-功能会影响已保存的记录吗" aria-label="Permalink to &quot;Q：打码 API Key 功能会影响已保存的记录吗？&quot;">​</a></h3><p>不会。打码功能只在<strong>复制操作</strong>时生效，即当你从详情面板复制请求体或响应体内容时，API Key 相关的字段值会被替换为 <code>***</code>。检查器界面中显示的原始内容不受影响，已保存的配置文件也不会被修改。</p><h3 id="q-检查器能捕获-https-流量吗" tabindex="-1">Q：检查器能捕获 HTTPS 流量吗？ <a class="header-anchor" href="#q-检查器能捕获-https-流量吗" aria-label="Permalink to &quot;Q：检查器能捕获 HTTPS 流量吗？&quot;">​</a></h3><p>LLM 检查器工作在应用层，它拦截的是你的 AI 客户端发出的 HTTP 请求，然后原样转发到目标 API 地址。由于你的客户端将请求发到了本地 HTTP 端口（<code>http://localhost:8999</code>），所以请求本身是明文 HTTP——但转发到目标 API 时仍然是 HTTPS。这种方式适合<strong>调试应用层协议内容</strong>，不适合也不用于解密别人的 HTTPS 流量。</p><h3 id="q-如何导出捕获的数据供其他人分析" tabindex="-1">Q：如何导出捕获的数据供其他人分析？ <a class="header-anchor" href="#q-如何导出捕获的数据供其他人分析" aria-label="Permalink to &quot;Q：如何导出捕获的数据供其他人分析？&quot;">​</a></h3><p>目前没有内置的导出功能。你可以：</p><ol><li>在记录详情面板中手动复制请求/响应内容</li><li>开启 <strong>API Key 打码</strong> 保护敏感信息后再复制分享</li><li>后续版本可能会添加导出功能</li></ol><h3 id="q-启动时提示-端口被占用-怎么办" tabindex="-1">Q：启动时提示&quot;端口被占用&quot;怎么办？ <a class="header-anchor" href="#q-启动时提示-端口被占用-怎么办" aria-label="Permalink to &quot;Q：启动时提示&quot;端口被占用&quot;怎么办？&quot;">​</a></h3><p>换一个端口号即可。常见被占用的端口有 <code>8999</code>、<code>3000</code>、<code>8080</code> 等，建议使用 <code>9000</code> 以上的端口，冲突概率较低。</p>`,100)])])}const u=a(l,[["render",i]]);export{g as __pageData,u as default};
